#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char S[N + 1];
        scanf("%s", S);
        int result = 0;
        int i = 0;
        while (i < strlen(S) - 1) {
            if (S[i] == '4' && S[i + 1] == '7') {
                result += i + 1;
                memmove(S + i, S + i + 2, strlen(S + i + 2) + 1);
            } else {
                i++;
            }
        }
        printf("%d\n", result);
    }
    return 0;
}

