int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        string S;
        cin >> S;
        int result = 0;
        int i = 0;
        while (i < S.length() - 1) {
            if (S[i] == '4' && S[i + 1] == '7') {
                result += i + 1;
                S.erase(i, 2);
            } else {
                i++;
            }
        }
        cout << result << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            String S = sc.next();
            int result = 0;
            int i = 0;
            while (i < S.length() - 1) {
                if (S.charAt(i) == '4' && S.charAt(i + 1) == '7') {
                    result += i + 1;
                    S = S.substring(0, i) + S.substring(i + 2);
                } else {
                    i++;
                }
            }
            System.out.println(result);
        }
    }
}

